          >
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
                background: 'rgba(2, 10, 24, 0.92)',
                border: `1px solid ${product.accentColor}66`,
                borderRadius: '6px',
                padding: '3px 10px 3px 8px',
                color: product.accentColor,
                fontSize: '11px',
                fontFamily: "'Rajdhani', 'Exo 2', sans-serif",
                fontWeight: '700',
                letterSpacing: '0.1em',
                whiteSpace: 'nowrap',
